module top_module (
    input [1:0] j,
    output reg invalid_t
);

    always @(*) begin
        case (j)
            2'b00: invalid_t = 1;
            2'b01: invalid_t = 1;
            2'b10: invalid_t = 0;
            2'b11: invalid_t = 0;
            default: invalid_t = 0; // Default case
        endcase
    end
endmodule
